            aOrbiterE = (((aWandererG + RotL64(aScatter, 5U)) + RotL64(aCarry, 3U)) + 0xD3A72836CE99B4AAULL) + aPhaseGOrbiterAssignSaltA[(((31U - aIndex) + 19U)) & S_SALT1];
