            //
            aOrbiterF = ((aOrbiterF + aOrbiterI) + 0xE741C61E3BE3CBD2ULL) + aPhaseGOrbiterUpdateSaltF[((aIndex + 11U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterF) ^ 0x42EA11540CE7E132ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x40FE069A94975C57ULL), 3U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterK) + 0xDF2FA8A1DB24E220ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterD) ^ 0x0BD271FD1765D79FULL) ^ aPhaseGOrbiterUpdateSaltB[((aIndex + 7U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0x3D8FB542A7F14AC9ULL), 41U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 0x0C7478342EFB5584ULL;
