            //
            aWandererD = aWandererD + ((RotL64(aPrevious, 53U) + aOrbiterJ) + RotL64(aOrbiterG, 51U));
            aWandererH = aWandererH ^ ((RotL64(aCross, 35U) + aOrbiterK) + RotL64(aOrbiterJ, 6U));
