            aOrbiterA = ((aWandererB + RotL64(aCross, 27U)) + 0xBCB48A6E56522069ULL) + aPhaseHOrbiterAssignSaltA[((aIndex + 29U)) & S_SALT1];
            aOrbiterD = (aWandererG + RotL64(aIngress, 11U)) + 0xB7207D527978F686ULL;
