            //
            aOrbiterG = ((aOrbiterG + aOrbiterH) + 0xDB318DCAA03A6360ULL) + aPhaseHOrbiterUpdateSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 0xE92D62ACCD83EBE5ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x658BD7556912E0B5ULL), 57U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterD) + 0x567F21A3509880CEULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 0x108FAF526AF3CEDCULL;
            aOrbiterB = RotL64((aOrbiterB * 0x343F50EC93752E71ULL), 3U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 0xBA513BF051A89854ULL;
