            aOrbiterD = RotL64((aOrbiterD * 0xA958923E330A33C1ULL), 35U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 0x877F4D2A5A347ABEULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0x64E6423E3CF995FCULL;
            aOrbiterC = RotL64((aOrbiterC * 0x5E103A7E85F7DDFDULL), 19U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterI) + 0xEB12B6A9606413F4ULL;
