            aOrbiterJ = RotL64((aOrbiterJ * 0x3A48AD19CCEDEC1BULL), 23U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterF) + 0xF5B82E97F4A54271ULL) + aPhaseHOrbiterUpdateSaltE[((aIndex + 3U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterJ) ^ 0x849A972E04C7A531ULL;
