            //
            aOrbiterD = (aOrbiterD + aOrbiterG) + 0xD3762678FB3E7F55ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterD) ^ 0xA1E9463054FE6F02ULL) ^ aPhaseHOrbiterUpdateSaltB[(((31U - aIndex) + 13U)) & S_SALT1];
