            aWandererD = aWandererD ^ (((RotL64(aPrevious, 57U) + RotL64(aOrbiterI, 41U)) + aOrbiterG) + aPhaseHWandererUpdateSaltA[((aIndex + 8U)) & S_SALT1]);
            aWandererF = aWandererF + ((((RotL64(aCross, 51U) + aOrbiterB) + RotL64(aOrbiterC, 19U)) + RotL64(aCarry, 51U)) + aPhaseHWandererUpdateSaltD[((aIndex + 21U)) & S_SALT1]);
            aWandererC = aWandererC ^ ((RotL64(aScatter, 41U) + RotL64(aOrbiterD, 47U)) + aOrbiterH);
